// ============================================================================
// generate-seed-sql.ts
//
// Walks every exported seed array in `src/lib/mock-data.ts` and emits the
// matching INSERT statements into `migrations/seed.sql`. Run with:
//     npx tsx scripts/generate-seed-sql.ts
//
// Re-run after bumping any mock-data. The generated file is deterministic —
// entities are written in dependency order so you can `wrangler d1 execute`
// it against a fresh D1 created from `migrations/0001_init.sql`.
// ============================================================================

import * as fs from "node:fs";
import * as path from "node:path";

import * as M from "../src/lib/mock-data";

// ---- SQL helpers ----------------------------------------------------------

const out: string[] = [];
let totalRows = 0;

function write(line: string): void {
  out.push(line);
}

function section(title: string): void {
  write("");
  write(`-- ========================================================`);
  write(`-- ${title}`);
  write(`-- ========================================================`);
}

/** Escape + quote a value for SQL. Numbers and booleans are inlined; strings
 *  get their single quotes doubled. `null` / `undefined` → NULL. */
function sqlVal(v: unknown): string {
  if (v === null || v === undefined) return "NULL";
  if (typeof v === "number") {
    if (!Number.isFinite(v)) return "NULL";
    return String(v);
  }
  if (typeof v === "boolean") return v ? "1" : "0";
  if (typeof v === "bigint") return v.toString();
  if (v instanceof Date) return `'${v.toISOString()}'`;
  // Arrays / objects that we pass through as JSON blobs:
  if (typeof v === "object") {
    return `'${JSON.stringify(v).replace(/'/g, "''")}'`;
  }
  return `'${String(v).replace(/'/g, "''")}'`;
}

/** Build an `INSERT INTO table (cols) VALUES (vals);` row. */
function insert(table: string, row: Record<string, unknown>): string {
  const cols = Object.keys(row);
  const vals = cols.map((c) => sqlVal(row[c]));
  return `INSERT INTO ${table} (${cols.join(", ")}) VALUES (${vals.join(", ")});`;
}

/** Emit a batch of rows + log progress. */
function emit(table: string, rows: Record<string, unknown>[]): void {
  if (rows.length === 0) {
    console.log(`Wrote 0 rows for ${table} (skipped empty)`);
    return;
  }
  for (const r of rows) write(insert(table, r));
  totalRows += rows.length;
  console.log(`Wrote ${rows.length} rows for ${table}`);
}

/** Bool → 0/1 (without clobbering already-numeric/null values). */
function b(v: unknown): number | null {
  if (v === undefined || v === null) return null;
  return v ? 1 : 0;
}

/** Coerce nullable optionals to null when missing. Also treats "" as null
 *  so empty-string FK references don't trigger constraint violations. */
function opt<T>(v: T | undefined | null): T | null {
  if (v === undefined || v === null) return null;
  if (typeof v === "string" && v === "") return null as unknown as T;
  return v;
}

// ---- Header --------------------------------------------------------------

write("-- Seed data for Hookka ERP — generated by scripts/generate-seed-sql.ts");
write("-- Regenerate with: npx tsx scripts/generate-seed-sql.ts");
// wrangler d1 execute --file wraps the whole file in a transaction, which
// silently disables `PRAGMA foreign_keys = OFF`. Use `defer_foreign_keys`
// instead — it postpones FK checks until COMMIT, which lets us insert
// children before parents when convenient.
write("BEGIN TRANSACTION;");
write("PRAGMA defer_foreign_keys = TRUE;");

