section("Customers + delivery hubs");
{
  const customerRows: Record<string, unknown>[] = [];
  const hubRows: Record<string, unknown>[] = [];
  for (const c of M.customers) {
    customerRows.push({
      id: c.id,
      code: c.code,
      name: c.name,
      ssmNo: opt(c.ssmNo),
      companyAddress: opt(c.companyAddress),
      creditTerms: opt(c.creditTerms),
      creditLimitSen: c.creditLimitSen,
      outstandingSen: c.outstandingSen,
      isActive: b(c.isActive),
      contactName: opt(c.contactName),
      phone: opt(c.phone),
      email: opt(c.email),
    });
    for (const h of c.deliveryHubs ?? []) {
      hubRows.push({
        id: h.id,
        customerId: c.id,
        code: h.code,
        shortName: h.shortName,
        state: h.state,
        address: h.address,
        contactName: h.contactName,
        phone: h.phone,
        email: h.email,
        isDefault: b(h.isDefault),
      });
    }
  }
  emit("customers", customerRows);
  emit("delivery_hubs", hubRows);
}

