section("Products + BOM components + dept working times");
{
  const productRows: Record<string, unknown>[] = [];
  const bomRows: Record<string, unknown>[] = [];
  const dwtRows: Record<string, unknown>[] = [];
  const subRows: Record<string, unknown>[] = [];
  for (const p of M.products) {
    productRows.push({
      id: p.id,
      code: p.code,
      name: p.name,
      category: p.category,
      description: opt(p.description),
      baseModel: opt(p.baseModel),
      sizeCode: opt(p.sizeCode),
      sizeLabel: opt(p.sizeLabel),
      fabricUsage: p.fabricUsage,
      unitM3: p.unitM3,
      status: p.status,
      costPriceSen: p.costPriceSen,
      basePriceSen: opt(p.basePriceSen),
      price1Sen: opt(p.price1Sen),
      productionTimeMinutes: p.productionTimeMinutes,
      subAssemblies: p.subAssemblies ?? [],
      skuCode: opt(p.skuCode),
      fabricColor: opt(p.fabricColor),
      pieces: opt(p.pieces),
      seatHeightPrices: opt(p.seatHeightPrices),
    });
    for (const bom of p.bomComponents ?? []) {
      bomRows.push({
        id: bom.id,
        productId: p.id,
        materialCategory: bom.materialCategory,
        materialName: bom.materialName,
        qtyPerUnit: bom.qtyPerUnit,
        unit: bom.unit,
        wastePct: bom.wastePct,
      });
      for (const sub of bom.substitutes ?? []) {
        subRows.push({
          bomComponentId: bom.id,
          bomTemplateWipId: null,
          materialId: opt(sub.materialId),
          materialName: sub.materialName,
          materialCategory: opt(sub.materialCategory),
          costDiffPercent: sub.costDiffPercent,
          priority: sub.priority,
          notes: opt(sub.notes),
        });
      }
    }
    for (const w of p.deptWorkingTimes ?? []) {
      dwtRows.push({
        productId: p.id,
        departmentCode: w.departmentCode,
        minutes: w.minutes,
        category: w.category,
      });
    }
  }
  emit("products", productRows);
  emit("bom_components", bomRows);
  emit("material_substitutes", subRows);
  emit("dept_working_times", dwtRows);
}

