section("Chart of accounts");
{
  // Parents first so FK check passes (self-ref). The seed data is already
  // roughly in top-down order (100-0000 before 100-0001, etc.) but sort on
  // parentCode presence just to be safe.
  const rows = [...(M.chartOfAccounts ?? [])].sort((a, b0) => {
    const aHasParent = a.parentCode ? 1 : 0;
    const bHasParent = b0.parentCode ? 1 : 0;
    return aHasParent - bHasParent;
  });
  emit(
    "chart_of_accounts",
    rows.map((a) => ({
      code: a.code,
      name: a.name,
      type: a.type,
      parentCode: opt(a.parentCode),
      balance: a.balance,
      isActive: b(a.isActive),
    })),
  );
}

