section("Production lead times (flat K/V)");
{
  const rows: Record<string, unknown>[] = [];
  const plt = M.productionLeadTimes;
  if (plt) {
    for (const [cat, map] of Object.entries(plt)) {
      for (const [dept, days] of Object.entries(map as Record<string, number>)) {
        rows.push({ category: cat, deptCode: dept, days });
      }
    }
  }
  emit("production_lead_times", rows);
}

